import React, { useEffect, useState } from "react";
import { Container, Table, Button, Form, Card, Modal, Spinner, Badge } from "react-bootstrap";
import { toast } from "react-toastify";
import api from "../services/api";

function Appointments() {
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [form, setForm] = useState({
    title: "",
    appointment_date: "",
    appointment_time: "",
    notes: "",
  });

  // Fetch appointments on load
  useEffect(() => {
    fetchAppointments();
  }, []);

  const fetchAppointments = async () => {
    try {
      const res = await api.get("/api/appointments");
      setAppointments(res.data);
    } catch (err) {
      console.error("❌ Fetch appointments error:", err);
      toast.error("Failed to load appointments");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!form.title || !form.appointment_date || !form.appointment_time) {
      toast.error("Title, date, and time are required");
      return;
    }

    setSubmitting(true);
    try {
      await api.post("/api/appointments", form);
      toast.success("Appointment added successfully");
      setForm({ title: "", appointment_date: "", appointment_time: "", notes: "" });
      setShowModal(false);
      fetchAppointments();
    } catch (err) {
      console.error("❌ Add appointment error:", err);
      toast.error(err.response?.data?.error || "Failed to add appointment");
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this appointment?")) return;

    try {
      await api.delete(`/api/appointments/${id}`);
      toast.success("Appointment deleted");
      fetchAppointments();
    } catch (err) {
      console.error("❌ Delete appointment error:", err);
      toast.error("Failed to delete appointment");
    }
  };

  // ✅ Improved logic to determine appointment status
  const getAppointmentStatus = (date, time) => {
    try {
      const [year, month, day] = date.split("-").map(Number);
      const [hours, minutes] = time.split(":").map(Number);
      const appointmentDateTime = new Date(year, month - 1, day, hours, minutes);
      const now = new Date();

      if (appointmentDateTime.toDateString() === now.toDateString()) {
        return appointmentDateTime > now ? "Today (Upcoming)" : "Today (Past)";
      }
      return appointmentDateTime > now ? "Upcoming" : "Past";
    } catch (e) {
      console.error("Date parse error:", e);
      return "Unknown";
    }
  };

  // ✅ Loading spinner
  if (loading) {
    return (
      <Container className="mt-4 text-center">
        <Spinner animation="border" variant="primary" />
        <p className="mt-2">Loading appointments...</p>
      </Container>
    );
  }

  return (
    <Container className="mt-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2>
            <i className="bi bi-calendar-event me-2"></i>
            Your Appointments
          </h2>
          <p className="text-muted">Manage your healthcare appointments</p>
        </div>
        <Button variant="primary" onClick={() => setShowModal(true)}>
          <i className="bi bi-plus-circle me-2"></i>
          Add Appointment
        </Button>
      </div>

      {appointments.length === 0 ? (
        <Card className="text-center p-5">
          <i className="bi bi-calendar-event text-muted" style={{ fontSize: "3rem" }}></i>
          <h4 className="mt-3">No appointments scheduled</h4>
          <p className="text-muted">Schedule your first appointment</p>
          <Button variant="primary" onClick={() => setShowModal(true)}>
            Add First Appointment
          </Button>
        </Card>
      ) : (
        <Table striped bordered hover responsive>
          <thead className="table-dark">
            <tr>
              <th>Title</th>
              <th>Date</th>
              <th>Time</th>
              <th>Notes</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {appointments.map((apt) => {
              const status = getAppointmentStatus(apt.appointment_date, apt.appointment_time);
              const variant = status.includes("Upcoming")
                ? "success"
                : status.includes("Today")
                ? "info"
                : "secondary";

              return (
                <tr key={apt.id}>
                  <td><strong>{apt.title}</strong></td>
                  <td>
                    {new Date(apt.appointment_date).toLocaleDateString(undefined, {
                      weekday: "short",
                      year: "numeric",
                      month: "short",
                      day: "numeric",
                    })}
                  </td>
                  <td>{apt.appointment_time}</td>
                  <td>{apt.notes || "-"}</td>
                  <td>
                    <Badge bg={variant}>{status}</Badge>
                  </td>
                  <td>
                    <Button
                      variant="danger"
                      size="sm"
                      onClick={() => handleDelete(apt.id)}
                    >
                      <i className="bi bi-trash"></i>
                    </Button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </Table>
      )}

      {/* Add Appointment Modal */}
      <Modal show={showModal} onHide={() => setShowModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Add New Appointment</Modal.Title>
        </Modal.Header>
        <Form onSubmit={handleSubmit}>
          <Modal.Body>
            <Form.Group className="mb-3">
              <Form.Label>Appointment Title</Form.Label>
              <Form.Control
                type="text"
                placeholder="e.g., Therapy Session"
                value={form.title}
                onChange={(e) => setForm({ ...form, title: e.target.value })}
                required
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Date</Form.Label>
              <Form.Control
                type="date"
                value={form.appointment_date}
                onChange={(e) => setForm({ ...form, appointment_date: e.target.value })}
                required
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Time</Form.Label>
              <Form.Control
                type="time"
                value={form.appointment_time}
                onChange={(e) => setForm({ ...form, appointment_time: e.target.value })}
                required
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Notes (Optional)</Form.Label>
              <Form.Control
                as="textarea"
                rows={3}
                placeholder="Additional notes..."
                value={form.notes}
                onChange={(e) => setForm({ ...form, notes: e.target.value })}
              />
            </Form.Group>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={() => setShowModal(false)} disabled={submitting}>
              Cancel
            </Button>
            <Button variant="primary" type="submit" disabled={submitting}>
              {submitting ? "Adding..." : "Add Appointment"}
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>
    </Container>
  );
}

export default Appointments;
